1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge: empty
6	  it("empty item list quote → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for single items (no modifiers, customer with no history triggers first-insurance surcharge; use loyalty 0 / no special)
15	  // We'll use a customer with yearsWithMHPCO=0 and treat first item — but first insurance surcharge and 10% surcharge apply.
16	  // For purely "base premium" verification we need cases that exercise base only. Use integration-style descriptions.
17	
18	  // Building block of 3 alike components — base premium only (these tests need a way to see just base premium; we instead use full quote with conditions that zero out other modifiers)
19	  // To verify base premium logic we use a long-standing customer scenario or just check the resulting premium reflects building block math.
20	
21	  // Building block examples (use customer 0yrs, first quote, no curse, no enchant → only first-insurance 10% + 5G fee)
22	  it.todo("quote 2 runes for new customer → premium = 50 base + 10% first insurance + 5 fee = 60 G");
23	  it.todo("quote 3 runes (block applies) → premium = 60 base + 10% first insurance + 5 fee = 71 G");
24	  it.todo("quote 4 runes (no block — block requires exactly 3) → premium = 100 base + 10% first insurance + 5 fee = 115 G");
25	  it.todo("quote 7 runes → premium = 175 base + 10% first insurance + 5 fee = 198 G (rounded up from 197.5)");
26	
27	  // Alike components clarification
28	  it.todo("quote 2 runes + 1 moonstone → no block (different types), base 75 G → premium 88 G");
29	  it.todo("quote 3 runes + 3 moonstones → two separate blocks, base 120 G → premium 137 G");
30	
31	  // Single item base premiums (verify each item type)
32	  it.todo("quote single sword (new customer) → 100 + 10 + 5 = 115 G");
33	  it.todo("quote single amulet (new customer) → 60 + 6 + 5 = 71 G");
34	  it.todo("quote single staff (new customer) → 80 + 8 + 5 = 93 G");
35	  it.todo("quote single potion (new customer) → 40 + 4 + 5 = 49 G");
36	
37	  // Modifier thresholds
38	  it.todo("customer with exactly 2 years gets loyalty discount");
39	  it.todo("sword with enchantment exactly 5 gets high-enchantment surcharge");
40	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
41	  it.todo("sword cursed and enchantment 5 → both surcharges apply");
42	
43	  // Modifier scope on multi-item policies
44	  it.todo("policy of cursed sword + plain amulet → 100 + 60 base = 160, cursed adds 50 (50% of sword only) = 210 before fee/other modifiers");
45	
46	  // Integration examples
47	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) → premium 165 G");
48	  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7, second quote) → premium 160 G");
49	
50	  // First insurance applies per item regardless of follow-up
51	  it.todo("each item in a quote is first insurance regardless of customer history");
52	
53	  // Rounding — premium
54	  it.todo("premium yielding 197.5 G is rounded up to 198 G (MHPCO's favor)");
55	
56	  // Claim: standard reimbursement
57	  it.todo("regular sword damage 500 → payout 400 (full minus 100 deductible)");
58	  it.todo("rune (no enchantment/material), damage 200 → payout 100");
59	
60	  // High enchantment vs dragon material
61	  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (50% then deductible)");
62	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins, then deductible)");
63	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon clause; full then deductible)");
64	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
65	
66	  // Deductible per damage event
67	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
68	
69	  // Multiple items of same type
70	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
71	  it.todo("dragon attack damages both swords (two entries) → each entry has its own deductible");
72	  it.todo("damages contains two sword entries but only one sword insured → CLI rejects with non-zero status");
73	
74	  // Cap exhaustion
75	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
76	  it.todo("cursed sword premium modifiers don't change cap → cap 2000 G");
77	  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount doesn't reduce insurance sum");
78	  it.todo("two successive 1500 claims on sword (cap 2000) → first payout 1400 (cap remaining 600), second 600 (cap 0)");
79	
80	  // Rounding — payout
81	  it.todo("payout yielding 350.5 G is rounded down to 350 G (MHPCO's favor)");
82	
83	  // Error edge cases
84	  it.todo("unknown item type in quote → CLI exits non-zero with stderr; no results on stdout");
85	  it.todo("claim damage references item not in policy → CLI exits non-zero with stderr");
86	  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
87	});
